      marker.on("click", () => {
        safeSetSuppress(320);
        onSelect(item.id);
      });

      markersRef.current[String(item.id)] = marker;
    });
  }, [hideClusterId, listings, onSelect, selectedId, spiderPoints]);

  return <div ref={hostRef} style={FILL_STYLE} />;
}

