import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Alert, Platform, useWindowDimensions } from "react-native";
import { router, useLocalSearchParams, type Href } from "expo-router";
import * as Location from "expo-location";
import type { Filters } from "./types";
import type {
  ListingRouteMeta,
  MapRegion,
  MapViewport,
  MarketListing,
  MyLoc,
} from "./mapContracts";
import { useMapListingsQuery } from "./useMapListingsQuery";
import {
  applyMapRouteFilters,
  buildClusterListings,
  buildSpiderPoints,
  defaultRegion,
  filterMapListings,
  findFocusedMapListing,
  getActiveMapFiltersCount,
  getFocusedMapRegion,
  getMapRegionForZoom,
  getMapZoomSteps,
  getRouteParamValue,
  normalizeListingRouteMeta,
  regionToBounds,
  resolveMapRowsForBottom,
  type MapClusterMode,
} from "./MapScreen.model";
import { loadMapScreenCurrentAuthUser } from "./MapScreen.auth.transport";
import {
  loadMapScreenListingRouteMeta,
  submitMapScreenDemandOffer,
} from "./MapScreen.market.transport";

import {
  buildIndex,
  getClusters,
  getClusterLeaves,
  getExpansionZoom,
  toClusterListing,
  zoomFromRegion,
} from "./pixelCluster";

export function useMapScreenController() {
  const { width: screenW } = useWindowDimensions();
  const params = useLocalSearchParams<{
    side?: string | string[];
    kind?: string | string[];
    city?: string | string[];
    focusId?: string | string[];
  }>();

  const { listings } = useMapListingsQuery();
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const [clusterMode, setClusterMode] = useState<MapClusterMode>(null);

  const [searchOpen, setSearchOpen] = useState(false);
  const [filtersOpen, setFiltersOpen] = useState(false);

  const [filters, setFilters] = useState<Filters>({
    side: "all",
    kind: "all",
    city: "",
    minPrice: null,
    maxPrice: null,
    catalogItem: null,
  });

  const activeFiltersCount = getActiveMapFiltersCount(filters);

  const [region, setRegion] = useState<MapRegion>(defaultRegion);
  const [myLoc, setMyLoc] = useState<MyLoc | null>(null);
  const routeMetaCacheRef = useRef<Map<string, ListingRouteMeta>>(new Map());

  // ✅ viewport всегда НЕ null и всегда с bounds
  const [viewport, setViewport] = useState<MapViewport>(() => ({
    zoom: zoomFromRegion(defaultRegion.longitudeDelta, 360),
    bounds: regionToBounds(defaultRegion),
  }));

  const [offerDemand, setOfferDemand] = useState<MarketListing | null>(null);
  const [demandDetails, setDemandDetails] = useState<MarketListing | null>(null);

  const [offerPrice, setOfferPrice] = useState("");
  const [offerDays, setOfferDays] = useState("");
  const [offerComment, setOfferComment] = useState("");
  const [sendingOffer, setSendingOffer] = useState(false);
  const routeSide = getRouteParamValue(params.side);
  const routeKind = getRouteParamValue(params.kind);
  const routeCity = getRouteParamValue(params.city);
  const routeFocusId = getRouteParamValue(params.focusId);

  // ✅ debounce region updates (пересчёт кластеров только когда карта “остановилась”)
  const regionTimerRef = useRef<{
    region: ReturnType<typeof setTimeout> | null;
    zoom: ReturnType<typeof setTimeout> | null;
  }>({ region: null, zoom: null });
  const onRegionChangeDebounced = (r: MapRegion) => {
    if (regionTimerRef.current.region) clearTimeout(regionTimerRef.current.region);
    regionTimerRef.current.region = setTimeout(() => {
      regionTimerRef.current.region = null;
      setRegion(r);

      const z = zoomFromRegion(r.longitudeDelta, screenW);
      setViewport((prev) => ({
        zoom: z,
        bounds: prev?.bounds ? prev.bounds : regionToBounds(r),
      }));
    }, 140);
  };

  useEffect(() => {
    const timers = regionTimerRef.current;
    return () => {
      if (timers.region) {
        clearTimeout(timers.region);
        timers.region = null;
      }
      if (timers.zoom) {
        clearTimeout(timers.zoom);
        timers.zoom = null;
      }
    };
  }, []);



  useEffect(() => {
    setFilters((prev) => applyMapRouteFilters(prev, {
      side: routeSide,
      kind: routeKind,
      city: routeCity,
    }));
  }, [routeCity, routeKind, routeSide]);

  // ===== filter =====
  const filteredListings = useMemo(() => filterMapListings(listings, filters), [listings, filters]);

  useEffect(() => {
    if (!routeFocusId) return;
    const match = findFocusedMapListing(routeFocusId, filteredListings, listings);
    if (!match) return;
    const focusedRegion = getFocusedMapRegion(match);
    if (!focusedRegion) return;
    setClusterMode(null);
    setSelectedId(match.id);
    setRegion(focusedRegion);
    if (match.side === "demand") setDemandDetails(match);
  }, [filteredListings, listings, routeFocusId]);

  // ===== supercluster index =====
  const clusterIndex = useMemo(() => buildIndex(filteredListings), [filteredListings]);

  // ===== clusters for viewport (pixel-based) =====
  const clusterFeatures = useMemo(() => {
    const b = viewport?.bounds;
    const z = viewport?.zoom;

    if (!b || b.west == null || b.east == null || b.south == null || b.north == null) return [];
    if (typeof z !== "number") return [];

    return getClusters(clusterIndex, b, z);
  }, [clusterIndex, viewport]);

  // ===== markers to draw =====
  const listingsForMap = useMemo(
    () => buildClusterListings(clusterFeatures, (count) => `НУЖНО (${count})`),
    [clusterFeatures],
  );

  // ===== bottom rows: либо clusterMode, либо все =====
  const rowsForBottom = useMemo(
    () => resolveMapRowsForBottom(clusterMode, filteredListings),
    [clusterMode, filteredListings],
  );

  // ===== spiderfy: если одинаковые координаты и zoom >= 17 =====
  const spiderPoints = useMemo(
    () => buildSpiderPoints({
      clusterMode,
      viewportZoom: viewport?.zoom,
      regionLongitudeDelta: region.longitudeDelta,
      screenWidth: screenW,
    }),
    [clusterMode, viewport?.zoom, region.longitudeDelta, screenW],
  );

  // ===== Zillow zoom helper (smooth 2-step) =====
  const zoomTo = (lat: number, lng: number, zTarget: number) => {
    const [z1, z2] = getMapZoomSteps(zTarget);
    const step1 = getMapRegionForZoom(lat, lng, z1, screenW);
    const step2 = getMapRegionForZoom(lat, lng, z2, screenW);

    setRegion(step1);
    if (regionTimerRef.current.zoom) clearTimeout(regionTimerRef.current.zoom);
    regionTimerRef.current.zoom = setTimeout(() => {
      regionTimerRef.current.zoom = null;
      setRegion(step2);
    }, 180);
  };

  // ===== double tap on cluster (extra zoom) =====
  const lastClusterTapRef = useRef<{ id: string; t: number } | null>(null);

  // ===== click handler =====
  const focusById = (id: string) => {
    // ✅ cluster click
    if (String(id).startsWith("cluster:")) {
      const clusterId = Number(String(id).split(":")[1]);
      const leaves = getClusterLeaves(clusterIndex, clusterId, 200);

      const items = leaves.map((leaf) => toClusterListing(leaf));
      const center = listingsForMap.find((item) => item.id === id);
      const lat = Number(center?.lat);
      const lng = Number(center?.lng);

      setDemandDetails(null);
      setSelectedId(null);

      setClusterMode({
        clusterId: id,
        title: `Спрос в этом месте: ${items.length}`,
        rows: items,
      });

      if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;

      // expansion zoom from supercluster
      const targetZoom = getExpansionZoom(clusterIndex, clusterId);

      // detect double tap
      const now = Date.now();
      const last = lastClusterTapRef.current;
      const isDouble = !!last && last.id === id && now - last.t < 320;
      lastClusterTapRef.current = { id, t: now };

      // ✅ single tap: smooth to expansionZoom
      // ✅ double tap: smooth to expansionZoom+1
      zoomTo(lat, lng, isDouble ? targetZoom + 1 : targetZoom);

      return;
    }

    // ✅ point click
    const targetItem =
      listingsForMap.find((item) => item.id === id) ||
      filteredListings.find((item) => item.id === id);

    if (!targetItem) return;
    if (targetItem.lat == null || targetItem.lng == null) return;

    setClusterMode(null);
    setSelectedId(id);

    setRegion({
      latitude: Number(targetItem.lat),
      longitude: Number(targetItem.lng),
      latitudeDelta: 0.05,
      longitudeDelta: 0.05,
    });

    if (targetItem.side === "demand") setDemandDetails(targetItem);
  };

  const goToMyLocation = async () => {
    if (Platform.OS === "web") {
      const geo = globalThis?.navigator?.geolocation;
      if (!geo) {
        Alert.alert("Геолокация", "Недоступно в этом браузере");
        return;
      }

      geo.getCurrentPosition(
        (pos: GeolocationPosition) => {
          const { latitude, longitude } = pos.coords;

          setMyLoc({
            latitude,
            longitude,
            heading: Number(pos.coords.heading ?? 0),
            accuracy: pos.coords.accuracy != null ? Number(pos.coords.accuracy) : null,
          });

          setSelectedId(null);
          setClusterMode(null);
          setRegion({ latitude, longitude, latitudeDelta: 0.05, longitudeDelta: 0.05 });
        },
        () => Alert.alert("Геолокация", "Нет доступа к геолокации"),
        { enableHighAccuracy: true, timeout: 8000 }
      );
      return;
    }

    const { status } = await Location.requestForegroundPermissionsAsync();
    if (status !== "granted") {
      Alert.alert("Геолокация", "Разрешение не выдано");
      return;
    }

    const pos = await Location.getCurrentPositionAsync({
      accuracy: Location.Accuracy.Balanced,
    });

    const { latitude, longitude } = pos.coords;

    setMyLoc({
      latitude,
      longitude,
      heading: Number(pos.coords.heading ?? 0),
      accuracy: pos.coords.accuracy != null ? Number(pos.coords.accuracy) : null,
    });

    setSelectedId(null);
    setClusterMode(null);
    setRegion({ latitude, longitude, latitudeDelta: 0.05, longitudeDelta: 0.05 });
  };

  const resetFilters = () => {
    setSelectedId(null);
    setClusterMode(null);
    setDemandDetails(null);

    setFilters({
      side: "all",
      kind: "all",
      city: "",
      minPrice: null,
      maxPrice: null,
      catalogItem: null,
    });
  };

  const openAssistant = useCallback(
    (row?: MarketListing | null) => {
      const selected =
        row ??
        demandDetails ??
        offerDemand ??
        filteredListings.find((item) => item.id === selectedId) ??
        null;

      const parts: string[] = ["Помоги сориентироваться по карте поставщиков GOX."];

      if (filters.side !== "all") parts.push(`Фильтр по стороне: ${filters.side}.`);
      if (filters.kind !== "all") parts.push(`Фильтр по типу: ${filters.kind}.`);
      if (filters.city.trim()) parts.push(`Город: ${filters.city.trim()}.`);
      if (filters.catalogItem?.name_human) {
        parts.push(`Каталожная позиция: ${filters.catalogItem.name_human}.`);
      }
      if (clusterMode?.title) {
        parts.push(`Сейчас открыт кластерный режим: ${clusterMode.title}.`);
      }
      if (selected) {
        parts.push(`Сейчас выделено объявление "${selected.title}".`);
        if (selected.city) parts.push(`Город объявления: ${selected.city}.`);
        parts.push(selected.side === "demand" ? "Это спрос." : "Это предложение.");
      } else {
        parts.push("Подскажи, как лучше использовать текущие фильтры и что открыть дальше.");
      }

      const href: Href = {
        pathname: "/(tabs)/ai",
        params: {
          prompt: parts.join(" "),
          autoSend: "1",
          context: "supplierMap",
        },
      };
      router.push(href);
    },
    [clusterMode?.title, demandDetails, filteredListings, filters, offerDemand, selectedId],
  );

  const submitOffer = async () => {
    if (!offerDemand) return;

    const priceNum = Number(String(offerPrice).replace(",", "."));
    if (!Number.isFinite(priceNum) || priceNum <= 0) {
      Alert.alert("Цена", "Введите корректную цену");
      return;
    }

    const daysNumRaw = offerDays.trim() ? Number(offerDays.trim()) : null;
    const deliveryDays =
      daysNumRaw != null && Number.isFinite(daysNumRaw) && daysNumRaw > 0 ? daysNumRaw : null;

    setSendingOffer(true);
    try {
      const user = await loadMapScreenCurrentAuthUser();
      if (!user) {
        Alert.alert("Вход", "Нужно войти в аккаунт");
        return;
      }

      const { error } = await submitMapScreenDemandOffer({
        demand_id: offerDemand.id,
        supplier_id: user.id,
        price: priceNum,
        delivery_days: deliveryDays,
        comment: offerComment || null,
      });

      if (error) {
        Alert.alert("Ошибка", error.message);
        return;
      }

      setOfferDemand(null);
      setOfferPrice("");
      setOfferDays("");
      setOfferComment("");
      Alert.alert("Готово", "Коммерческое предложение отправлено");
    } finally {
      setSendingOffer(false);
    }
  };

  const resolveListingRouteMeta = useCallback(async (row: Pick<MarketListing, "id" | "title">) => {
    const cached = routeMetaCacheRef.current.get(row.id);
    if (cached) return cached;

    const result = await loadMapScreenListingRouteMeta(row.id);

    if (result.error) throw result.error;
    const nextMeta = normalizeListingRouteMeta(result.data);
    if (!nextMeta) return null;
    routeMetaCacheRef.current.set(row.id, nextMeta);
    return nextMeta;
  }, []);

  const openListingDetails = useCallback((row: Pick<MarketListing, "id">) => {
    const href: Href = { pathname: "/product/[id]", params: { id: row.id } };
    router.push(href);
  }, []);

  const openListingChat = useCallback((row: Pick<MarketListing, "id" | "title">) => {
    const href: Href = {
      pathname: "/chat",
      params: {
        listingId: row.id,
        title: row.title,
      },
    };
    router.push(href);
  }, []);

  const openListingShowcase = useCallback(
    async (row: Pick<MarketListing, "id" | "title">) => {
      try {
        const meta = await resolveListingRouteMeta(row);
        if (!meta?.user_id) {
          Alert.alert("Р’РёС‚СЂРёРЅР°", "РќРµ СѓРґР°Р»РѕСЃСЊ РЅР°Р№С‚Рё РїСЂРѕС„РёР»СЊ РїРѕСЃС‚Р°РІС‰РёРєР°.");
          return;
        }

        const href: Href = {
          pathname: "/supplierShowcase",
          params: {
            userId: meta.user_id,
            ...(meta.company_id ? { companyId: meta.company_id } : {}),
          },
        };
        router.push(href);
      } catch (error: unknown) {
        const message =
          error instanceof Error ? error.message : "РќРµ СѓРґР°Р»РѕСЃСЊ РѕС‚РєСЂС‹С‚СЊ РІРёС‚СЂРёРЅСѓ РїРѕСЃС‚Р°РІС‰РёРєР°.";
        Alert.alert("Р’РёС‚СЂРёРЅР°", message);
      }
    },
    [resolveListingRouteMeta],
  );

  return {
    listingsForMap,
    spiderPoints,
    clusterMode,
    selectedId,
    region,
    myLoc,
    focusById,
    onRegionChangeDebounced,
    setViewport,
    filters,
    activeFiltersCount,
    searchOpen,
    setSearchOpen,
    filtersOpen,
    setFiltersOpen,
    filteredListings,
    setClusterMode,
    setSelectedId,
    setFilters,
    resetFilters,
    rowsForBottom,
    setRegion,
    openListingDetails,
    openListingShowcase,
    openListingChat,
    setOfferDemand,
    demandDetails,
    setDemandDetails,
    openAssistant,
    goToMyLocation,
    offerDemand,
    offerPrice,
    setOfferPrice,
    offerDays,
    setOfferDays,
    offerComment,
    setOfferComment,
    sendingOffer,
    submitOffer,
  };
}

export type MapScreenController = ReturnType<typeof useMapScreenController>;

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Alert, Platform, useWindowDimensions } from "react-native";
import { router, useLocalSearchParams, type Href } from "expo-router";
import * as Location from "expo-location";
import type { Filters } from "./types";
import type {
  ListingRouteMeta,
  MapRegion,
  MapViewport,
  MarketListing,
  MyLoc,
} from "./mapContracts";
import { useMapListingsQuery } from "./useMapListingsQuery";
import {
  applyMapRouteFilters,
  buildClusterListings,
  buildSpiderPoints,
  defaultRegion,
  filterMapListings,
  findFocusedMapListing,
  getActiveMapFiltersCount,
  getFocusedMapRegion,
  getMapRegionForZoom,
  getMapZoomSteps,
  getRouteParamValue,
  normalizeListingRouteMeta,
  regionToBounds,
  resolveMapRowsForBottom,
  type MapClusterMode,
} from "./MapScreen.model";
import { loadMapScreenCurrentAuthUser } from "./MapScreen.auth.transport";
import {
  loadMapScreenListingRouteMeta,
  submitMapScreenDemandOffer,
} from "./MapScreen.market.transport";

import {
  buildIndex,
  getClusters,
  getClusterLeaves,
  getExpansionZoom,
  toClusterListing,
  zoomFromRegion,
} from "./pixelCluster";

export function useMapScreenController() {
  const { width: screenW } = useWindowDimensions();
  const params = useLocalSearchParams<{
    side?: string | string[];
    kind?: string | string[];
    city?: string | string[];
    focusId?: string | string[];
  }>();

  const { listings } = useMapListingsQuery();
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const [clusterMode, setClusterMode] = useState<MapClusterMode>(null);

  const [searchOpen, setSearchOpen] = useState(false);
  const [filtersOpen, setFiltersOpen] = useState(false);

  const [filters, setFilters] = useState<Filters>({
    side: "all",
    kind: "all",
    city: "",
    minPrice: null,
    maxPrice: null,
    catalogItem: null,
  });

  const activeFiltersCount = getActiveMapFiltersCount(filters);

  const [region, setRegion] = useState<MapRegion>(defaultRegion);
  const [myLoc, setMyLoc] = useState<MyLoc | null>(null);
  const routeMetaCacheRef = useRef<Map<string, ListingRouteMeta>>(new Map());

  // ✅ viewport всегда НЕ null и всегда с bounds
  const [viewport, setViewport] = useState<MapViewport>(() => ({
    zoom: zoomFromRegion(defaultRegion.longitudeDelta, 360),
    bounds: regionToBounds(defaultRegion),
  }));

  const [offerDemand, setOfferDemand] = useState<MarketListing | null>(null);
  const [demandDetails, setDemandDetails] = useState<MarketListing | null>(null);

  const [offerPrice, setOfferPrice] = useState("");
  const [offerDays, setOfferDays] = useState("");
  const [offerComment, setOfferComment] = useState("");
  const [sendingOffer, setSendingOffer] = useState(false);
  const routeSide = getRouteParamValue(params.side);
  const routeKind = getRouteParamValue(params.kind);
  const routeCity = getRouteParamValue(params.city);
  const routeFocusId = getRouteParamValue(params.focusId);

  // ✅ debounce region updates (пересчёт кластеров только когда карта “остановилась”)
  const regionTimerRef = useRef<{
    region: ReturnType<typeof setTimeout> | null;
    zoom: ReturnType<typeof setTimeout> | null;
  }>({ region: null, zoom: null });
  const onRegionChangeDebounced = (r: MapRegion) => {
    if (regionTimerRef.current.region) clearTimeout(regionTimerRef.current.region);
    regionTimerRef.current.region = setTimeout(() => {
      regionTimerRef.current.region = null;
      setRegion(r);

      const z = zoomFromRegion(r.longitudeDelta, screenW);
      setViewport((prev) => ({
        zoom: z,
        bounds: prev?.bounds ? prev.bounds : regionToBounds(r),
      }));
    }, 140);
  };

  useEffect(() => {
    const timers = regionTimerRef.current;
    return () => {
      if (timers.region) {
        clearTimeout(timers.region);
        timers.region = null;
      }
      if (timers.zoom) {
        clearTimeout(timers.zoom);
        timers.zoom = null;
      }
    };
  }, []);



  useEffect(() => {
    setFilters((prev) => applyMapRouteFilters(prev, {
      side: routeSide,
      kind: routeKind,
      city: routeCity,
    }));
  }, [routeCity, routeKind, routeSide]);

  // ===== filter =====
  const filteredListings = useMemo(() => filterMapListings(listings, filters), [listings, filters]);

  useEffect(() => {
    if (!routeFocusId) return;
    const match = findFocusedMapListing(routeFocusId, filteredListings, listings);
    if (!match) return;
    const focusedRegion = getFocusedMapRegion(match);
    if (!focusedRegion) return;
    setClusterMode(null);
    setSelectedId(match.id);
    setRegion(focusedRegion);
    if (match.side === "demand") setDemandDetails(match);
  }, [filteredListings, listings, routeFocusId]);

  // ===== supercluster index =====
  const clusterIndex = useMemo(() => buildIndex(filteredListings), [filteredListings]);

  // ===== clusters for viewport (pixel-based) =====
  const clusterFeatures = useMemo(() => {
    const b = viewport?.bounds;
    const z = viewport?.zoom;

    if (!b || b.west == null || b.east == null || b.south == null || b.north == null) return [];
    if (typeof z !== "number") return [];

    return getClusters(clusterIndex, b, z);
  }, [clusterIndex, viewport]);

  // ===== markers to draw =====
  const listingsForMap = useMemo(
    () => buildClusterListings(clusterFeatures, (count) => `НУЖНО (${count})`),
    [clusterFeatures],
  );

  // ===== bottom rows: либо clusterMode, либо все =====
  const rowsForBottom = useMemo(
    () => resolveMapRowsForBottom(clusterMode, filteredListings),
    [clusterMode, filteredListings],
  );

  // ===== spiderfy: если одинаковые координаты и zoom >= 17 =====
  const spiderPoints = useMemo(
    () => buildSpiderPoints({
      clusterMode,
      viewportZoom: viewport?.zoom,
      regionLongitudeDelta: region.longitudeDelta,
      screenWidth: screenW,
    }),
    [clusterMode, viewport?.zoom, region.longitudeDelta, screenW],
  );

  // ===== Zillow zoom helper (smooth 2-step) =====
  const zoomTo = (lat: number, lng: number, zTarget: number) => {
    const [z1, z2] = getMapZoomSteps(zTarget);
    const step1 = getMapRegionForZoom(lat, lng, z1, screenW);
    const step2 = getMapRegionForZoom(lat, lng, z2, screenW);

    setRegion(step1);
    if (regionTimerRef.current.zoom) clearTimeout(regionTimerRef.current.zoom);
    regionTimerRef.current.zoom = setTimeout(() => {
      regionTimerRef.current.zoom = null;
      setRegion(step2);
    }, 180);
  };

  // ===== double tap on cluster (extra zoom) =====
  const lastClusterTapRef = useRef<{ id: string; t: number } | null>(null);

  // ===== click handler =====
  const focusById = (id: string) => {
    // ✅ cluster click
    if (String(id).startsWith("cluster:")) {
      const clusterId = Number(String(id).split(":")[1]);
      const leaves = getClusterLeaves(clusterIndex, clusterId, 200);

      const items = leaves.map((leaf) => toClusterListing(leaf));
      const center = listingsForMap.find((item) => item.id === id);
      const lat = Number(center?.lat);
      const lng = Number(center?.lng);

      setDemandDetails(null);
      setSelectedId(null);

      setClusterMode({
        clusterId: id,
        title: `Спрос в этом месте: ${items.length}`,
        rows: items,
      });

      if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;

      // expansion zoom from supercluster
      const targetZoom = getExpansionZoom(clusterIndex, clusterId);

      // detect double tap
      const now = Date.now();
      const last = lastClusterTapRef.current;
      const isDouble = !!last && last.id === id && now - last.t < 320;
      lastClusterTapRef.current = { id, t: now };

      // ✅ single tap: smooth to expansionZoom
      // ✅ double tap: smooth to expansionZoom+1
      zoomTo(lat, lng, isDouble ? targetZoom + 1 : targetZoom);

      return;
    }

    // ✅ point click
    const targetItem =
      listingsForMap.find((item) => item.id === id) ||
      filteredListings.find((item) => item.id === id);

    if (!targetItem) return;
    if (targetItem.lat == null || targetItem.lng == null) return;

    setClusterMode(null);
    setSelectedId(id);

    setRegion({
      latitude: Number(targetItem.lat),
      longitude: Number(targetItem.lng),
      latitudeDelta: 0.05,
      longitudeDelta: 0.05,
    });

    if (targetItem.side === "demand") setDemandDetails(targetItem);
  };

  const goToMyLocation = async () => {
    if (Platform.OS === "web") {
      const geo = globalThis?.navigator?.geolocation;
      if (!geo) {
        Alert.alert("Геолокация", "Недоступно в этом браузере");
        return;
      }

      geo.getCurrentPosition(
        (pos: GeolocationPosition) => {
          const { latitude, longitude } = pos.coords;

          setMyLoc({
            latitude,
            longitude,
            heading: Number(pos.coords.heading ?? 0),
            accuracy: pos.coords.accuracy != null ? Number(pos.coords.accuracy) : null,
          });

          setSelectedId(null);
          setClusterMode(null);
          setRegion({ latitude, longitude, latitudeDelta: 0.05, longitudeDelta: 0.05 });
        },
        () => Alert.alert("Геолокация", "Нет доступа к геолокации"),
        { enableHighAccuracy: true, timeout: 8000 }
      );
      return;
    }

    const { status } = await Location.requestForegroundPermissionsAsync();
    if (status !== "granted") {
      Alert.alert("Геолокация", "Разрешение не выдано");
      return;
    }

    const pos = await Location.getCurrentPositionAsync({
      accuracy: Location.Accuracy.Balanced,
    });

    const { latitude, longitude } = pos.coords;

    setMyLoc({
      latitude,
      longitude,
      heading: Number(pos.coords.heading ?? 0),
      accuracy: pos.coords.accuracy != null ? Number(pos.coords.accuracy) : null,
    });

    setSelectedId(null);
    setClusterMode(null);
    setRegion({ latitude, longitude, latitudeDelta: 0.05, longitudeDelta: 0.05 });
  };

  const resetFilters = () => {
    setSelectedId(null);
    setClusterMode(null);
    setDemandDetails(null);

    setFilters({
      side: "all",
      kind: "all",
      city: "",
      minPrice: null,
      maxPrice: null,
      catalogItem: null,
    });
  };

  const openAssistant = useCallback(
    (row?: MarketListing | null) => {
      const selected =
        row ??
        demandDetails ??
        offerDemand ??
        filteredListings.find((item) => item.id === selectedId) ??
        null;

      const parts: string[] = ["Помоги сориентироваться по карте поставщиков GOX."];

      if (filters.side !== "all") parts.push(`Фильтр по стороне: ${filters.side}.`);
      if (filters.kind !== "all") parts.push(`Фильтр по типу: ${filters.kind}.`);
      if (filters.city.trim()) parts.push(`Город: ${filters.city.trim()}.`);
      if (filters.catalogItem?.name_human) {
        parts.push(`Каталожная позиция: ${filters.catalogItem.name_human}.`);
      }
      if (clusterMode?.title) {
        parts.push(`Сейчас открыт кластерный режим: ${clusterMode.title}.`);
      }
      if (selected) {
        parts.push(`Сейчас выделено объявление "${selected.title}".`);
        if (selected.city) parts.push(`Город объявления: ${selected.city}.`);
        parts.push(selected.side === "demand" ? "Это спрос." : "Это предложение.");
      } else {
        parts.push("Подскажи, как лучше использовать текущие фильтры и что открыть дальше.");
      }

      const href: Href = {
        pathname: "/(tabs)/ai",
        params: {
          prompt: parts.join(" "),
          autoSend: "1",
          context: "supplierMap",
        },
      };
      router.push(href);
    },
    [clusterMode?.title, demandDetails, filteredListings, filters, offerDemand, selectedId],
  );

  const submitOffer = async () => {
    if (!offerDemand) return;

    const priceNum = Number(String(offerPrice).replace(",", "."));
    if (!Number.isFinite(priceNum) || priceNum <= 0) {
      Alert.alert("Цена", "Введите корректную цену");
      return;
    }

    const daysNumRaw = offerDays.trim() ? Number(offerDays.trim()) : null;
    const deliveryDays =
      daysNumRaw != null && Number.isFinite(daysNumRaw) && daysNumRaw > 0 ? daysNumRaw : null;

    setSendingOffer(true);
    try {
      const user = await loadMapScreenCurrentAuthUser();
      if (!user) {
        Alert.alert("Вход", "Нужно войти в аккаунт");
        return;
      }

      const { error } = await submitMapScreenDemandOffer({
        demand_id: offerDemand.id,
        supplier_id: user.id,
        price: priceNum,
        delivery_days: deliveryDays,
        comment: offerComment || null,
      });

      if (error) {
        Alert.alert("Ошибка", error.message);
        return;
      }

      setOfferDemand(null);
      setOfferPrice("");
      setOfferDays("");
      setOfferComment("");
      Alert.alert("Готово", "Коммерческое предложение отправлено");
    } finally {
      setSendingOffer(false);
    }
  };

  const resolveListingRouteMeta = useCallback(async (row: Pick<MarketListing, "id" | "title">) => {
    const cached = routeMetaCacheRef.current.get(row.id);
    if (cached) return cached;

    const result = await loadMapScreenListingRouteMeta(row.id);

    if (result.error) throw result.error;
    const nextMeta = normalizeListingRouteMeta(result.data);
    if (!nextMeta) return null;
    routeMetaCacheRef.current.set(row.id, nextMeta);
    return nextMeta;
  }, []);

  const openListingDetails = useCallback((row: Pick<MarketListing, "id">) => {
    const href: Href = { pathname: "/product/[id]", params: { id: row.id } };
    router.push(href);
  }, []);

  const openListingChat = useCallback((row: Pick<MarketListing, "id" | "title">) => {
    const href: Href = {
      pathname: "/chat",
      params: {
        listingId: row.id,
        title: row.title,
      },
    };
    router.push(href);
  }, []);

  const openListingShowcase = useCallback(
    async (row: Pick<MarketListing, "id" | "title">) => {
      try {
        const meta = await resolveListingRouteMeta(row);
        if (!meta?.user_id) {
          Alert.alert("Р’РёС‚СЂРёРЅР°", "РќРµ СѓРґР°Р»РѕСЃСЊ РЅР°Р№С‚Рё РїСЂРѕС„РёР»СЊ РїРѕСЃС‚Р°РІС‰РёРєР°.");
          return;
        }

        const href: Href = {
          pathname: "/supplierShowcase",
          params: {
            userId: meta.user_id,
            ...(meta.company_id ? { companyId: meta.company_id } : {}),
          },
        };
        router.push(href);
      } catch (error: unknown) {
        const message =
          error instanceof Error ? error.message : "РќРµ СѓРґР°Р»РѕСЃСЊ РѕС‚РєСЂС‹С‚СЊ РІРёС‚СЂРёРЅСѓ РїРѕСЃС‚Р°РІС‰РёРєР°.";
        Alert.alert("Р’РёС‚СЂРёРЅР°", message);
      }
    },
    [resolveListingRouteMeta],
  );

  return {
    listingsForMap,
    spiderPoints,
    clusterMode,
    selectedId,
    region,
    myLoc,
    focusById,
    onRegionChangeDebounced,
    setViewport,
    filters,
    activeFiltersCount,
    searchOpen,
    setSearchOpen,
    filtersOpen,
    setFiltersOpen,
    filteredListings,
    setClusterMode,
    setSelectedId,
    setFilters,
    resetFilters,
    rowsForBottom,
    setRegion,
    openListingDetails,
    openListingShowcase,
    openListingChat,
    setOfferDemand,
    demandDetails,
    setDemandDetails,
    openAssistant,
    goToMyLocation,
    offerDemand,
    offerPrice,
    setOfferPrice,
    offerDays,
    setOfferDays,
    offerComment,
    setOfferComment,
    sendingOffer,
    submitOffer,
  };
}

export type MapScreenController = ReturnType<typeof useMapScreenController>;

import type { AiModelClient } from "./AiModelClient";
import { DisabledModelProvider } from "./DisabledModelProvider";
import { LegacyGeminiModelProvider } from "./LegacyGeminiModelProvider";
import {
  resolveAiModelProviderId,
  type AiModelProviderEnv,
} from "./aiModelProviderFlags";
import type {
  AiModelMessage,
  AiModelProviderId,
  AiModelRequest,
  AiModelResponse,
} from "./AiModelTypes";

export const AI_MODEL_MAX_OUTPUT_TOKENS = 2048;
export const AI_MODEL_TIMEOUT_MS = 30000;
export const AI_MODEL_MAX_MESSAGES = 32;
export const AI_MODEL_MESSAGE_CONTENT_CHAR_LIMIT = 12000;

type AiModelGatewayOptions = {
  provider?: AiModelClient;
  providerId?: AiModelProviderId;
  env?: AiModelProviderEnv;
  legacyGeminiModel?: string | null;
};

const blockedResponse = (
  reason: string,
  provider: AiModelProviderId = "disabled",
  model = "blocked",
): AiModelResponse => ({
  provider,
  model,
  text: "",
  safety: {
    redacted: true,
    blocked: true,
    reason,
  },
});

const normalizeMessage = (message: AiModelMessage): AiModelMessage => ({
  role: message.role,
  content: String(message.content ?? ""),
});

const validateRequest = (request: AiModelRequest): string | null => {
  if (request.redactionRequired !== true) {
    return "AI model request redaction is required";
  }
  if (!Array.isArray(request.messages) || request.messages.length === 0) {
    return "AI model request messages are required";
  }
  if (request.messages.length > AI_MODEL_MAX_MESSAGES) {
    return "AI model request message count exceeded";
  }
  if (!Number.isFinite(request.maxOutputTokens) || request.maxOutputTokens <= 0) {
    return "AI model request maxOutputTokens is invalid";
  }
  if (request.maxOutputTokens > AI_MODEL_MAX_OUTPUT_TOKENS) {
    return "AI model request maxOutputTokens exceeded";
  }
  if (!Number.isFinite(request.timeoutMs) || request.timeoutMs <= 0) {
    return "AI model request timeoutMs is invalid";
  }
  if (request.timeoutMs > AI_MODEL_TIMEOUT_MS) {
    return "AI model request timeoutMs exceeded";
  }
  if (!Number.isFinite(request.temperature)) {
    return "AI model request temperature is invalid";
  }
  const oversizedMessage = request.messages.find(
    (message) => String(message.content ?? "").length > AI_MODEL_MESSAGE_CONTENT_CHAR_LIMIT,
  );
  if (oversizedMessage) {
    return "AI model request message content exceeded";
  }
  return null;
};

const withTimeout = async (
  promise: Promise<AiModelResponse>,
  timeoutMs: number,
): Promise<AiModelResponse> =>
  await new Promise<AiModelResponse>((resolve, reject) => {
    const timeout = setTimeout(() => {
      reject(new Error("AI model provider timed out."));
    }, timeoutMs);
    promise.then(
      (value) => {
        clearTimeout(timeout);
        resolve(value);
      },
      (error) => {
        clearTimeout(timeout);
        reject(error);
      },
    );
  });

export class AiModelGateway {
  private readonly client: AiModelClient;

  constructor(options?: AiModelGatewayOptions) {
    this.client = options?.provider ?? AiModelGateway.createProvider(options);
  }

  static createProvider(options?: AiModelGatewayOptions): AiModelClient {
    const providerId = options?.providerId ?? resolveAiModelProviderId(options?.env);
    if (providerId === "legacy_gemini") {
      return new LegacyGeminiModelProvider({ model: options?.legacyGeminiModel });
    }
    return new DisabledModelProvider();
  }

  isAvailable(): boolean {
    if (this.client.providerId === "disabled") return false;
    if (this.client instanceof LegacyGeminiModelProvider) {
      return this.client.isConfigured();
    }
    return true;
  }

  async generate(request: AiModelRequest): Promise<AiModelResponse> {
    const validationError = validateRequest(request);
    if (validationError) {
      return blockedResponse(validationError, this.client.providerId);
    }

    const normalizedRequest: AiModelRequest = {
      ...request,
      messages: request.messages.map(normalizeMessage),
    };

    try {
      const response = await withTimeout(
        this.client.generate(normalizedRequest),
        Math.min(request.timeoutMs, AI_MODEL_TIMEOUT_MS),
      );
      return {
        provider: response.provider,
        model: String(response.model || this.client.providerId),
        text: String(response.text || ""),
        structured: response.structured,
        usage: response.usage,
        safety: {
          redacted: response.safety.redacted === true,
          blocked: response.safety.blocked === true,
          reason: response.safety.reason,
        },
      };
    } catch (error) {
      const reason = error instanceof Error ? error.message : "AI model provider failed";
      return blockedResponse(reason, this.client.providerId);
    }
  }
}

export function isAiModelGatewayAvailable(options?: AiModelGatewayOptions): boolean {
  return new AiModelGateway(options).isAvailable();
}

import { Platform } from "react-native";
import * as Print from "expo-print";
import type { FilePrintResult } from "expo-print";
import { File, Paths } from "expo-file-system";
import { createCancellableDelay } from "../async/mapWithConcurrencyLimit";
import { normalizeLocalFileUri } from "../pdfFileContract";

type OpenDocOpts = { share?: boolean };

const logPdfDebug = (level: "info" | "warn", message: string, payload: Record<string, unknown>) => {
  if (!__DEV__) return;
  // eslint-disable-next-line no-console
  console[level](message, payload);
};

const uiYield = async (ms = 0) => {
  await createCancellableDelay(ms).promise;
};

const withTimeout = async <T,>(p: Promise<T>, ms: number, msg: string): Promise<T> => {
  let t: ReturnType<typeof setTimeout> | undefined;
  const timeout = new Promise<T>((_, reject) => {
    t = setTimeout(() => reject(new Error(msg)), ms);
  });
  try {
    return await Promise.race([p, timeout]);
  } finally {
    if (t) clearTimeout(t);
  }
};

const resolvePrintResultUri = (result: FilePrintResult): string => {
  const uri = result.uri?.trim() ?? "";
  if (!uri) {
    throw new Error("printToFileAsync returned empty uri");
  }
  return uri;
};

export async function openHtmlAsPdfUniversal(
  html: string,
  _opts: OpenDocOpts = {},
): Promise<string> {
  try {
    if (Platform.OS === "web") {
      const blob = new Blob([html], { type: "text/html;charset=utf-8" });
      return URL.createObjectURL(blob);
    }

    await uiYield(50);
    logPdfDebug("info", "[pdf-api] native_print_requested", {
      stage: "native_print_requested",
      platform: Platform.OS,
      htmlLength: String(html || "").length,
    });

    const res = await withTimeout(
      Print.printToFileAsync({ html }),
      35000,
      "PDF generates too slowly. Try again.",
    );

    const rawUri = resolvePrintResultUri(res);

    if ((Platform.OS as string) !== "web") {
      const sourceUri = normalizeLocalFileUri(rawUri);
      const stableName = `gen_${Date.now()}_${Math.random().toString(36).substring(2, 9)}.pdf`;
      const sourceFile = new File(sourceUri);
      const destinationFile = new File(Paths.cache, stableName);
      const copiedUri = destinationFile.uri;

      let lastError: unknown;
      for (let attempt = 1; attempt <= 3; attempt++) {
        try {
          if (attempt > 1) await uiYield(200 * attempt);
          if (destinationFile.exists) {
            destinationFile.delete();
          }
          sourceFile.copy(destinationFile);
          const copiedInfo = destinationFile.info();
          if (!copiedInfo?.exists) {
            throw new Error("Generated PDF copy is missing after File API materialization");
          }
          logPdfDebug("info", "[pdf-api] native_print_materialized", {
            stage: "native_print_materialized",
            platform: Platform.OS,
            rawUri,
            copiedUri,
            attempt,
          });
          return copiedUri;
        } catch (e) {
          lastError = e;
          logPdfDebug("warn", "[pdf-api] native_print_materialize_failed", {
            stage: "native_print_materialize_failed",
            platform: Platform.OS,
            rawUri,
            copiedUri,
            attempt,
            error: e instanceof Error ? e.message : String(e),
          });
        }
      }
      throw lastError ?? new Error("Failed to materialize generated PDF into app cache");
    }

    return rawUri;
  } catch (error) {
    const message =
      error && typeof error === "object" && "message" in error && typeof (error as { message?: unknown }).message === "string"
        ? String((error as { message?: unknown }).message || "").trim()
        : String(error ?? "").trim() || "PDF generation failed";
    if (__DEV__) console.error("[pdf-api] native_print_failed", {
      stage: "native_print_failed",
      platform: Platform.OS,
      htmlLength: String(html || "").length,
      errorName: error && typeof error === "object" && "name" in error ? String((error as { name?: unknown }).name || "") : "",
      errorMessage: message,
    });
    throw new Error(message);
  }
}

export type ConcurrencyLimitOptions = {
  label?: string;
};

const normalizeLimit = (limit: number, itemCount: number) => {
  const parsed = Math.floor(Number(limit));
  if (!Number.isFinite(parsed) || parsed <= 0) {
    throw new Error("mapWithConcurrencyLimit limit must be a positive number");
  }
  return Math.max(1, Math.min(parsed, Math.max(1, itemCount)));
};

export async function mapWithConcurrencyLimit<T, R>(
  items: readonly T[],
  limit: number,
  worker: (item: T, index: number) => Promise<R>,
  _options?: ConcurrencyLimitOptions,
): Promise<R[]> {
  const source = Array.isArray(items) ? items : Array.from(items);
  if (!source.length) return [];

  const concurrency = normalizeLimit(limit, source.length);
  const results = new Array<R>(source.length);
  let nextIndex = 0;

  const run = async () => {
    while (nextIndex < source.length) {
      const index = nextIndex;
      nextIndex += 1;
      results[index] = await worker(source[index], index);
    }
  };

  await Promise.all(Array.from({ length: concurrency }, () => run()));
  return results;
}

export async function allSettledWithConcurrencyLimit<T, R>(
  items: readonly T[],
  limit: number,
  worker: (item: T, index: number) => Promise<R>,
  options?: ConcurrencyLimitOptions,
): Promise<PromiseSettledResult<R>[]> {
  return mapWithConcurrencyLimit(
    items,
    limit,
    async (item, index): Promise<PromiseSettledResult<R>> => {
      try {
        return {
          status: "fulfilled",
          value: await worker(item, index),
        };
      } catch (reason) {
        return {
          status: "rejected",
          reason,
        };
      }
    },
    options,
  );
}

export const MIN_WORKER_LOOP_BACKOFF_MS = 1;

export type WorkerLoopClock = {
  sleep: (ms: number, signal?: AbortSignal | null) => Promise<void>;
};

export type WorkerLoopIterationContext = {
