  urlToLocal.clear();
  activeRuns.clear();
}

function getErrorMessage(error: unknown, fallback: string): string {
  if (error instanceof Error) {
    const message = error.message.trim();
    if (message) return message;
  }
  if (typeof error === "string") {
    const message = error.trim();
    if (message) return message;
  }
  return fallback;
}

const uiYield = async (ms = 0) => {
  await createCancellableDelay(ms).promise;
};

/**
 * Wait for all in-flight UI transitions (screen animations, modal
 * presentations) to settle. On iOS this prevents share sheets
 * and navigation pushes from appearing behind the current screen.
 * Falls back to immediate resolve when InteractionManager is unavailable
 * (Jest, web, or missing native module).
 */
const waitForInteractions = (): Promise<void> =>
  new Promise<void>((resolve) => {
    if (typeof InteractionManager?.runAfterInteractions === "function") {
      InteractionManager.runAfterInteractions(() => resolve());
    } else {
      resolve();
    }
  });

const withTimeout = async <T,>(p: Promise<T>, ms: number, msg: string): Promise<T> => {
  let t: ReturnType<typeof setTimeout> | undefined;
  const timeout = new Promise<T>((_, reject) => {
    t = setTimeout(() => reject(new Error(msg)), ms);
  });
  try {
    return await Promise.race([p, timeout]);
  } finally {
    if (t) clearTimeout(t);
  }
};

function normalizeRemoteUrl(raw: unknown) {
  return String(raw || "").trim().replace(/^"+|"+$/g, "").trim();
}

function logPdfRunnerStage(
  stage: string,
  payload: {
    uri?: string | null;
    exists?: boolean;
    size?: number;
    sourceKind: PdfSourceKind;
    fileName?: string;
  },
) {
  if (__DEV__) console.info(`[pdf-runner] ${stage}`, {
    stage,
    uri: payload.uri ? redactSensitiveText(payload.uri) : null,
    scheme: getUriScheme(payload.uri),
    exists: payload.exists,
    sizeBytes: payload.size,
    sourceKind: payload.sourceKind,
    fileName: payload.fileName ?? null,
  });
}

const recordPdfRunnerCatch = (params: {
  kind: "critical_fail" | "soft_failure" | "cleanup_only" | "degraded_fallback";
  event: string;
  error: unknown;
  category?: "fetch" | "ui" | "reload";
  sourceKind?: string;
  errorStage?: string;
  extra?: Record<string, unknown>;
}) =>
  recordCatchDiscipline({
    screen: "reports",
    surface: "pdf_runner",
    event: params.event,
    kind: params.kind,
    error: params.error,
    category: params.category,
    sourceKind: params.sourceKind ?? "pdf:runner",
    errorStage: params.errorStage ?? params.event,
    extra: params.extra,
  });

function getFileInfoSize(
  info:
    | (Awaited<ReturnType<typeof FileSystemCompat.getInfoAsync>>)
    | null
    | undefined,
): number | undefined {
  if (!info || !("size" in info)) return undefined;
  const value = Number(info.size);
  return Number.isFinite(value) ? value : undefined;
}

function safeName(name?: string, stableSeed?: string) {
  const fallbackHash = hashString32(String(name || stableSeed || "pdf"));
  return normalizePdfFileName(name, `pdf_${fallbackHash}.pdf`);
}

async function resolvePdfSource(args: {
  source?: PdfSource;
  resolveSource?: () => Promise<PdfSource> | PdfSource;
  getRemoteUrl?: () => Promise<string> | string;
}): Promise<PdfSource> {
  if (args.source) return args.source;
  if (args.resolveSource) return await Promise.resolve(args.resolveSource());

  const remote = await Promise.resolve(args.getRemoteUrl?.());
  const url = normalizeRemoteUrl(remote);
  if (!url) throw new Error("PDF source URI is empty");
  return createPdfSource(url);
}

async function ensureNativePdfHandoffUri(uri: string, fileName?: string): Promise<string> {
  const value = String(uri || "").trim();
  if (!value) throw new Error("PDF handoff URI is empty");
  if (Platform.OS === "web") return value;

  const scheme = getUriScheme(value);
  if (scheme === "blob" || scheme === "data") {
    throw new Error("Native handoff cannot use blob/data PDF URI");
  }

  let localUri = value;
  if (isHttpUri(value)) {
    const paths = getFileSystemPaths();
    const cacheDir = paths.cacheDir;
    const targetUri = `${cacheDir}handoff_${hashString32(value)}_${safeName(fileName, value)}`;
    const downloaded = await FileSystemCompat.downloadAsync(value, targetUri);
    localUri = String(downloaded?.uri || targetUri);
  }

  let normalizedLocalUri = normalizeLocalFileUri(localUri);
  const info = await FileSystemCompat.getInfoAsync(normalizedLocalUri);
  if (!info?.exists) throw new Error("Native handoff source PDF file is missing");

  if (!/\.pdf$/i.test(normalizedLocalUri)) {
    const paths = getFileSystemPaths();
    const cacheDir = paths.cacheDir;
    const targetUri = `${cacheDir}handoff_${hashString32(normalizedLocalUri)}_${safeName(fileName, normalizedLocalUri)}`;
    if (!(await fileExists(targetUri))) {
      await FileSystemCompat.copyAsync({ from: normalizedLocalUri, to: targetUri });
    }
    normalizedLocalUri = normalizeLocalFileUri(targetUri);
  }

  await assertValidLocalPdfFile({
    fileSystem: FileSystemCompat,
    uri: normalizedLocalUri,
    failureLabel: "Native handoff PDF",
    mode: Platform.OS === "ios" ? "size-only" : "content-probe",
  });

  return normalizedLocalUri;
}

async function openAndroidPdfContentUri(localUri: string, fileName?: string): Promise<string> {
  const handoffUri = await ensureNativePdfHandoffUri(localUri, fileName);
  if (!FileSystemCompat.getContentUriAsync) {
    throw new Error("Android local PDF handoff requires getContentUriAsync support");
  }
  const contentUri = await FileSystemCompat.getContentUriAsync(handoffUri);
  logPdfRunnerStage("pdf_android_content_uri_ready", {
    uri: contentUri,
    sourceKind: "local-file",
    fileName,
  });
  await openAndroidViewIntent(contentUri, "application/pdf", {
    owner: "pdf-runner",
    fileName: fileName ?? null,
  });
  return contentUri;
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars
async function openAndroidRemotePdfUrl(remoteUrl: string, fileName?: string): Promise<string> {
  const normalizedUrl = normalizeRemoteUrl(remoteUrl);
  if (!isHttpUri(normalizedUrl)) {
    throw new Error("Android remote PDF handoff requires an http(s) URL");
  }
  logPdfRunnerStage("pdf_android_remote_url_open_start", {
    uri: normalizedUrl,
    sourceKind: "remote-url",
    fileName,
  });
  try {
    await Linking.openURL(normalizedUrl);
    logPdfRunnerStage("pdf_android_remote_url_open_ready", {
      uri: normalizedUrl,
      sourceKind: "remote-url",
      fileName,
    });
    return normalizedUrl;
  } catch (error) {
    recordPdfRunnerCatch({
      kind: "critical_fail",
      event: "pdf_android_remote_url_open_failed",
      error,
      category: "ui",
      sourceKind: "remote-url",
      errorStage: "open_view",
      extra: {
        uri: normalizedUrl,
        fileName: fileName ?? null,
      },
    });
    throw error instanceof Error ? error : new Error(String(error ?? "Android remote PDF open failed"));
  }
}

async function openIosPdfShareSheet(localUri: string, fileName?: string, dialogTitle = "Открыть PDF") {
  const handoffUri = await ensureNativePdfHandoffUri(localUri, fileName);
  if (getUriScheme(handoffUri) !== "file") {
    throw new Error("iOS PDF share requires a local file:// handoff.");
  }
  const info = await FileSystemCompat.getInfoAsync(handoffUri);
  const sizeBytes = getFileInfoSize(info);
  if (!Number.isFinite(sizeBytes) || !sizeBytes || sizeBytes <= 0) {
    throw new Error("iOS PDF share file is empty.");
  }
  if (sizeBytes > IOS_PDF_SHARE_MAX_BYTES) {
    logPdfRunnerStage("pdf_ios_share_size_guard_triggered", {
      uri: handoffUri,
      exists: true,
      size: sizeBytes,
      sourceKind: "local-file",
      fileName,
    });
    recordPdfRunnerCatch({
      kind: "degraded_fallback",
      event: "pdf_ios_share_size_guard_triggered",
      error: new Error(`PDF file too large for share sheet: ${sizeBytes} bytes`),
      category: "ui",
      sourceKind: "local-file",
      errorStage: "ios_share_size_guard",
      extra: { sizeBytes, maxBytes: IOS_PDF_SHARE_MAX_BYTES, fileName: fileName ?? null },
    });
    await new Promise<void>((resolve) => {
      Alert.alert(
        "Большой файл",
        `PDF слишком большой для предпросмотра (${Math.round(sizeBytes / 1024 / 1024)} МБ). Открыть через системный просмотрщик?`,
        [
          { text: "Отмена", style: "cancel", onPress: () => resolve() },
          {
            text: "Открыть",
            onPress: async () => {
              try {
                await Linking.openURL(handoffUri);
              } catch (linkError) {
                recordPdfRunnerCatch({
                  kind: "critical_fail",
                  event: "pdf_ios_share_size_guard_linking_failed",
                  error: linkError,
                  category: "ui",
                  sourceKind: "local-file",
                  errorStage: "ios_share_size_guard_fallback",
                  extra: { uri: handoffUri, fileName: fileName ?? null },
                });
              }
              resolve();
            },
          },
        ],
      );
    });
    return;
  }
  logPdfRunnerStage("pdf_ios_share_handoff_ready", {
    uri: handoffUri,
    exists: Boolean(info?.exists),
    size: sizeBytes,
    sourceKind: "local-file",
    fileName,
  });
  const canShare = await Sharing.isAvailableAsync();
  if (!canShare) {
    throw new Error("Sharing is unavailable on this device");
  }
  // Wait for all in-flight UI transitions (screen animations, modal
  // presentations) to settle before presenting the iOS share sheet.
  // Without this, the UIActivityViewController can appear behind the
  // current screen when triggered during a navigation transition.
  await waitForInteractions();
  await Sharing.shareAsync(handoffUri, {
    mimeType: "application/pdf",
    UTI: "com.adobe.pdf",
    dialogTitle,
  });
}


async function fileExists(uri: string) {
  try {
    const info = await FileSystemCompat.getInfoAsync(uri);
    return !!info?.exists;
  } catch (error) {
    recordPdfRunnerCatch({
      kind: "cleanup_only",
      event: "pdf_file_exists_probe_failed",
      error,
      category: "reload",
      sourceKind: "local-file",
      extra: {
        uri,
      },
    });
    return false;
  }
}

async function getAuthHeader(supabase: PdfSupabaseLike) {
  try {
    const { data } = await readPdfRunnerAuthSession(supabase);
    const token = data?.session?.access_token;
    const headers: Record<string, string> = {};
    if (SUPABASE_ANON_KEY) headers.apikey = SUPABASE_ANON_KEY;
    if (token) headers.Authorization = `Bearer ${token}`;
    return Object.keys(headers).length ? headers : undefined;
  } catch (error) {
    recordPdfRunnerCatch({
      kind: "degraded_fallback",
      event: "pdf_auth_header_fallback",
      error,
      category: "fetch",
      sourceKind: "supabase:auth",
      extra: {
        hasAnonKey: Boolean(SUPABASE_ANON_KEY),
      },
    });
    return SUPABASE_ANON_KEY ? { apikey: SUPABASE_ANON_KEY } : undefined;
  }
}

export async function preparePdfExecutionSource(args: {
  supabase: PdfSupabaseLike;
  source?: PdfSource;
  resolveSource?: () => Promise<PdfSource> | PdfSource;
  getRemoteUrl?: () => Promise<string> | string;
  fileName?: string;
}): Promise<PdfSource> {
  const source = await resolvePdfSource(args);
  const url = source.uri;
  logPdfRunnerStage("pdf_source_received", {
    uri: url,
    sourceKind: source.kind,
    fileName: args.fileName,
  });

  if (Platform.OS === "web") return source;
  if (source.kind === "blob") {
    throw new Error("Native execution cannot use blob/data PDF source");
  }
  if (source.kind === "local-file") {
    logPdfRunnerStage("pdf_source_classified_local", {
      uri: url,
      sourceKind: "local-file",
      fileName: args.fileName,
    });
    const normalizedLocalUri = normalizeLocalFileUri(url);
    logPdfRunnerStage("pdf_local_uri_normalized", {
      uri: normalizedLocalUri,
      sourceKind: "local-file",
      fileName: args.fileName,
    });
    return createPdfSource(normalizedLocalUri);
  }
  logPdfRunnerStage("pdf_source_classified_remote", {
    uri: url,
    sourceKind: "remote-url",
    fileName: args.fileName,
  });

  if (Platform.OS === "android" || Platform.OS === "ios") {
    // Keep backend-owned remote URLs intact for the mobile viewer/open boundary.
    // Mobile preview can hand them off directly without forcing a local file session first.
    return source;
  }

  const cached = urlToLocal.get(url);
  if (cached && (await fileExists(cached))) {
    const normalizedCachedUri = normalizeLocalFileUri(cached);
    const info = await FileSystemCompat.getInfoAsync(normalizedCachedUri);
    logPdfRunnerStage("pdf_download_exists_yes", {
      uri: normalizedCachedUri,
      exists: Boolean(info?.exists),
      size: getFileInfoSize(info),
      sourceKind: "local-file",
      fileName: args.fileName,
    });
    return createPdfSource(normalizedCachedUri);
  }

  const baseName = safeName(args.fileName, url);
  const localName = baseName.replace(/\.pdf$/i, `_${hashString32(url)}.pdf`);
  const paths = getFileSystemPaths();
  const cacheDir = paths.cacheDir;

  if (!cacheDir) {
    throw new Error(`FileSystem directory unavailable (Native module not initialized?). Available keys: ${Object.keys(FileSystemCompat || {}).join(", ")}`);
  }
  const localOutput = `${cacheDir}${localName}`;

  if (await fileExists(localOutput)) {
    const normalizedLocalOutput = normalizeLocalFileUri(localOutput);
    urlToLocal.set(url, normalizedLocalOutput);
    return createPdfSource(normalizedLocalOutput);
  }

  const headers = await getAuthHeader(args.supabase);
  logPdfRunnerStage("pdf_download_started", {
    uri: localOutput,
    sourceKind: "remote-url",
    fileName: args.fileName,
  });
  const dl = await FileSystemCompat.downloadAsync(url, localOutput, { headers });
  const uri = normalizeLocalFileUri(dl?.uri || localOutput);
  logPdfRunnerStage("pdf_download_done", {
    uri,
    sourceKind: "local-file",
    fileName: args.fileName,
  });
  const info = await FileSystemCompat.getInfoAsync(uri);
  const exists = Boolean(info?.exists);
  logPdfRunnerStage(exists ? "pdf_download_exists_yes" : "pdf_download_exists_no", {
    uri,
    exists,
    size: getFileInfoSize(info),
    sourceKind: "local-file",
    fileName: args.fileName,
  });
  if (!exists) throw new Error("Downloaded PDF file does not exist after download");
  urlToLocal.set(url, uri);
  return createPdfSource(uri);
}

export async function preparePdfLocalUri(args: {
  supabase: PdfSupabaseLike;
  source?: PdfSource;
  resolveSource?: () => Promise<PdfSource> | PdfSource;
  getRemoteUrl?: () => Promise<string> | string;
  fileName?: string;
}): Promise<string> {
  return (await preparePdfExecutionSource(args)).uri;
}

export async function openPdfPreview(localUri: string, fileName?: string) {
  if (Platform.OS === "web") {
    const win = window.open(localUri, "_blank");
    if (!win) {
      Alert.alert("PDF", "Разреши всплывающие окна (pop-up).");
      throw new Error("PDF popup window was blocked");
    }
    return;
  }

  if (Platform.OS === "android") {
    if (isHttpUri(localUri)) {
      await openAndroidRemotePdfUrlBoundary(localUri, {
        owner: "pdf-runner",
        fileName: fileName ?? null,
      });
      return;
    }
    await openAndroidPdfContentUri(localUri, fileName);
    return;
  }

  throw new Error("iOS PDF preview must use the in-app viewer route");
}

export async function openPdfShare(localUri: string, fileName?: string) {
  if (Platform.OS === "web") {
    const win = window.open(localUri, "_blank");
    if (!win) {
      Alert.alert("PDF", "Разреши всплывающие окна (pop-up).");
      throw new Error("PDF popup window was blocked");
    }
    return;
  }

  if (Platform.OS === "ios") {
    await openIosPdfShareSheet(localUri, fileName, "Поделиться PDF");
    return;
  }

  const handoffUri = await ensureNativePdfHandoffUri(localUri, fileName);
  const canShare = await Sharing.isAvailableAsync();
  if (!canShare) throw new Error("Sharing is unavailable on this device");
  await Sharing.shareAsync(handoffUri, {
    mimeType: "application/pdf",
    UTI: "com.adobe.pdf",
    dialogTitle: "Поделиться PDF",
  });
}

export async function openPdfExternal(localUri: string, fileName?: string) {
  if (Platform.OS === "web") {
    await openPdfPreview(localUri, fileName);
    return;
  }

  if (Platform.OS === "android") {
    if (isHttpUri(localUri)) {
      await openAndroidRemotePdfUrlBoundary(localUri, {
        owner: "pdf-runner",
        fileName: fileName ?? null,
      });
      return;
    }
    await openAndroidPdfContentUri(localUri, fileName);
    return;
  }

  await openIosPdfShareSheet(localUri, fileName, "Открыть PDF");
}

export async function runPdfTop(args: {
  busy?: BusyLike;
  supabase: PdfSupabaseLike;
  key: string;
  label: string;
  mode: "preview" | "share";
  fileName?: string;
  getRemoteUrl: () => Promise<string> | string;
}) {
  const { busy, supabase, key, label, mode, fileName, getRemoteUrl } = args;
  const observation = beginPlatformObservability({
    screen: "reports",
    surface: "pdf_runner",
    category: "ui",
    event: mode === "share" ? "share_pdf" : "preview_pdf",
    sourceKind: "pdf:runner",
  });

  if (activeRuns.has(key)) return;
  activeRuns.add(key);

  const cleanup = () => {
    activeRuns.delete(key);
  };

  if (Platform.OS === "web") {
    const sourceObservation = beginPdfLifecycleObservation({
      screen: "reports",
      surface: "pdf_runner",
      event: "pdf_runner_source_load",
      stage: "source_load",
      category: "fetch",
      sourceKind: "pdf:runner",
      context: {
        documentFamily: "pdf_runner",
        fileName: fileName ?? null,
      },
    });
    const openObservation = beginPdfLifecycleObservation({
      screen: "reports",
      surface: "pdf_runner",
      event: "pdf_runner_open_view",
      stage: "open_view",
      category: "ui",
      sourceKind: "pdf:web_popup",
      context: {
        documentFamily: "pdf_runner",
        fileName: fileName ?? null,
      },
    });
    let win: Window | null = null;
    try {
      win = window.open("", "_blank");
    } catch (error) {
      recordPdfRunnerCatch({
        kind: "soft_failure",
        event: "pdf_window_open_failed",
        error,
        category: "ui",
        extra: {
          key,
          mode,
        },
      });
      win = null;
    }

    if (!win) {
      const popupError = new Error("PDF popup window was blocked");
      recordPdfRunnerCatch({
        kind: "critical_fail",
        event: "pdf_popup_blocked",
        error: popupError,
        category: "ui",
        extra: {
          key,
          mode,
        },
      });
      observation.error(popupError, {
        sourceKind: "pdf:web_popup",
        errorStage: "window_open",
        extra: {
          key,
          mode,
          publishState: "error",
        },
      });
      openObservation.error(popupError, {
        fallbackMessage: "PDF popup window was blocked",
        errorStage: "window_open",
        extra: {
          key,
          mode,
          publishState: "error",
        },
      });
      Alert.alert("PDF", "Разреши всплывающие окна (pop-up).");
      cleanup();
      return;
    }

    try {
      win.document.open();
      win.document.write(`<!doctype html><meta charset="utf-8"/>
        <title>PDF</title>
        <body style="font-family:system-ui;padding:16px">
          <b>${label || "Формируем PDF..."}</b>
          <div style="opacity:.7;margin-top:6px">Если долго, проверь соединение.</div>
        </body>`);
      win.document.close();
    } catch (error) {
      recordPdfRunnerCatch({
        kind: "cleanup_only",
        event: "pdf_placeholder_render_failed",
        error,
        category: "ui",
        extra: {
          key,
          mode,
        },
      });
    }

    try {
      const remote = await withTimeout(
        Promise.resolve(getRemoteUrl()),
        15000,
        "Server did not respond in 15 seconds",
      );
      const url = normalizeRemoteUrl(remote);
      if (!url) throw new Error("PDF URL is empty");
      sourceObservation.success({
        sourceKind: "remote-url",
        extra: {
          key,
          mode,
          remoteUrl: url,
        },
      });
      try {
        win.location.replace(url);
      } catch (error) {
        recordPdfRunnerCatch({
          kind: "degraded_fallback",
          event: "pdf_window_replace_failed",
          error,
          category: "ui",
          extra: {
            key,
            mode,
            url,
          },
        });
        win.location.href = url;
      }
      win.focus();
      openObservation.success({
        sourceKind: "remote-url",
        extra: {
          key,
          mode,
          publishState: "ready",
        },
      });
      observation.success({
        sourceKind: "remote-url",
        extra: {
          key,
          mode,
          publishState: "ready",
        },
      });
      cleanup();
      return;
    } catch (caughtError: unknown) {
      const error = { message: getErrorMessage(caughtError, "Не удалось открыть PDF") };
      sourceObservation.error(caughtError, {
        fallbackMessage: "PDF source load failed",
        extra: {
          key,
          mode,
          publishState: "error",
        },
      });
      recordPdfRunnerCatch({
        kind: "critical_fail",
        event: "pdf_web_open_failed",
        error: caughtError,
        category: "ui",
        extra: {
          key,
          mode,
        },
      });
      observation.error(caughtError, {
        sourceKind: "pdf:web_open",
        errorStage: "open_remote_url",
        extra: {
          key,
          mode,
          publishState: "error",
        },
      });
      try {
        win.close();
      } catch (closeError) {
        recordPdfRunnerCatch({
          kind: "cleanup_only",
          event: "pdf_window_close_failed",
          error: closeError,
          category: "reload",
          extra: {
            key,
            mode,
          },
        });
      }
      Alert.alert("PDF", error?.message ?? "Не удалось открыть PDF");
      cleanup();
      return;
    }
  }

  const doPrepare = async () => {
    await uiYield(50);
    return await withTimeout(
      preparePdfLocalUri({ supabase, getRemoteUrl, fileName }),
      25000,
      "PDF готовится слишком долго. Попробуй еще раз.",
    );
  };
  const prepareObservation = beginPdfLifecycleObservation({
    screen: "reports",
    surface: "pdf_runner",
    event: "pdf_runner_output_prepare",
    stage: "output_prepare",
    category: "fetch",
    sourceKind: "pdf:runner",
    context: {
      documentFamily: "pdf_runner",
      fileName: fileName ?? null,
    },
  });
  const openObservation = beginPdfLifecycleObservation({
    screen: "reports",
    surface: "pdf_runner",
    event: "pdf_runner_open_view",
    stage: "open_view",
    category: "ui",
    sourceKind: "pdf:native_open",
    context: {
      documentFamily: "pdf_runner",
      fileName: fileName ?? null,
    },
  });

  try {
    let localUri: string | null = null;
    if (busy?.run) {
      localUri = await busy.run(doPrepare, { key, label, minMs: 650 });
    } else {
      busy?.show?.(key, label);
      try {
        localUri = await doPrepare();
      } finally {
        busy?.hide?.(key);
      }
    }

    if (!localUri) {
      cleanup();
      return;
    }
    prepareObservation.success({
      sourceKind: "local-file",
      extra: {
        key,
        mode,
        localUri,
      },
    });

    await uiYield(Platform.OS === "ios" ? 120 : 40);
    try {
      if (mode === "share") await openPdfShare(localUri, fileName);
      else await openPdfPreview(localUri, fileName);
      openObservation.success({
        sourceKind: "local-file",
        extra: {
          key,
          mode,
          publishState: "ready",
        },
      });
    } catch (openError) {
      throw openObservation.error(openError, {
        fallbackMessage: "PDF open failed",
        extra: {
          key,
          mode,
          publishState: "error",
        },
      });
    }
  } catch (caughtError: unknown) {
    const error = { message: getErrorMessage(caughtError, "Не удалось открыть PDF") };
    if (!(caughtError instanceof Error && caughtError.name === "PdfLifecycleError")) {
      prepareObservation.error(caughtError, {
        fallbackMessage: "PDF preparation failed",
        extra: {
          key,
          mode,
          publishState: "error",
        },
      });
    }
    recordPdfRunnerCatch({
      kind: "critical_fail",
      event: "pdf_prepare_or_open_failed",
      error: caughtError,
      category: "ui",
      extra: {
        key,
        mode,
      },
    });
    observation.error(caughtError, {
      sourceKind: "pdf:native_open",
      errorStage: "prepare_or_open",
      extra: {
        key,
        mode,
        publishState: "error",
      },
    });
    Alert.alert("PDF", String(error?.message ?? "Не удалось открыть PDF"));
  } finally {
    registerTimeout("pdf-runner:post-open-cleanup", cleanup, 500);
  }
}

import { beginPlatformObservability } from "./observability/platformObservability";

type PlatformObservabilityInput = Parameters<typeof beginPlatformObservability>[0];
type PlatformScreen = PlatformObservabilityInput["screen"];

export type RequestTimeoutClass =
  | "lightweight_lookup"
  | "ui_scope_load"
  | "heavy_report_or_pdf_or_storage"
  | "mutation_request";

export type RequestTimeoutEndpointKind =
  | "supabase_rpc"
  | "supabase_rest"
  | "supabase_storage"
  | "supabase_function"
  | "supabase_auth"
  | "direct_fetch";

export type RequestTimeoutPolicyRecord = Record<RequestTimeoutClass, number>;

export const REQUEST_TIMEOUT_POLICY_MS: Readonly<RequestTimeoutPolicyRecord> = Object.freeze({
  lightweight_lookup: 8_000,
  ui_scope_load: 20_000,
  heavy_report_or_pdf_or_storage: 60_000,
  mutation_request: 30_000,
});

export const REQUEST_TIMEOUT_POLICY_COMPAT_DEFAULT_CLASS: RequestTimeoutClass = "ui_scope_load";

const LIGHTWEIGHT_RPC_NAMES = new Set([
  "ensure_my_profile",
  "get_my_role",
  "resolve_catalog_synonym_v1",
  "resolve_packaging_v1",
  "rik_quick_ru",
  "rik_quick_search",
  "rik_quick_search_typed",
  "suppliers_list",
  "request_display",
  "request_display_no",
  "request_label",
]);

const HEAVY_RPC_PATTERNS = [
  /^pdf_/i,
  /^acc_report_/i,
  /^wh_report_/i,
  /^director_.*report/i,
  /^warehouse_.*report/i,
];

const UI_SCOPE_RPC_PATTERNS = [
  /_scope(_v\d+)?$/i,
  /^list_/i,
  /_window(_v\d+)?$/i,
  /_summary(_v\d+)?$/i,
  /_source(_v\d+)?$/i,
  /^request_items_by_request$/i,
  /^proposal_attachments_list$/i,
  /^proposal_attachment_evidence_scope_v1$/i,
  /^resolve_req_pr_map$/i,
  /^marketplace_item_scope_detail_v1$/i,
];

const MUTATION_RPC_PATTERNS = [
  /(^|_)(submit|create|add|set|update|delete|remove|approve|reject|return|publish|commit|apply|mark|seed|sync|issue|receive|send|claim|recover|attach|upload)(_|$)/i,
];

const HEAVY_FUNCTION_PATTERNS = [/pdf/i, /report/i, /storage/i];

export const REQUEST_TIMEOUT_CLASS_MAP = Object.freeze({
  compatibilityDefault: {
    requestClass: REQUEST_TIMEOUT_POLICY_COMPAT_DEFAULT_CLASS,
    timeoutMs: REQUEST_TIMEOUT_POLICY_MS[REQUEST_TIMEOUT_POLICY_COMPAT_DEFAULT_CLASS],
    reason: "fallback when no stricter request-class rule matches",
  },
  classes: {
    lightweight_lookup: {
      timeoutMs: REQUEST_TIMEOUT_POLICY_MS.lightweight_lookup,
      owners: [
        "supabase rpc exact lightweight lookups",
        "supabase auth GET session/profile probes",
      ],
      ruleExamples: [
        "rpc:get_my_role",
        "rpc:ensure_my_profile",
        "rpc:rik_quick_search_typed",
      ],
    },
    ui_scope_load: {
      timeoutMs: REQUEST_TIMEOUT_POLICY_MS.ui_scope_load,
      owners: [
        "supabase rest GET reads",
        "scope/list/window/source RPC reads",
      ],
      ruleExamples: [
        "rest:get",
        "rpc:director_pending_proposals_scope_v1",
        "rpc:accountant_inbox_scope_v1",
      ],
    },
    heavy_report_or_pdf_or_storage: {
      timeoutMs: REQUEST_TIMEOUT_POLICY_MS.heavy_report_or_pdf_or_storage,
      owners: [
        "pdf/report source RPCs",
        "storage upload/download/signed-url flows",
        "direct PDF backend fetches",
      ],
      ruleExamples: [
        "rpc:pdf_payment_source_v1",
        "functions:director-production-report-pdf",
        "storage:/storage/v1/object/*",
      ],
    },
    mutation_request: {
      timeoutMs: REQUEST_TIMEOUT_POLICY_MS.mutation_request,
      owners: [
        "write RPCs and non-GET rest mutations",
        "auth POST flows",
      ],
      ruleExamples: [
        "rpc:request_submit",
        "rpc:proposal_send_to_accountant_min",
        "rest:post",
      ],
    },
  },
});

type RequestTimeoutParams = {
  requestClass?: RequestTimeoutClass;
  timeoutMsOverride?: number;
  owner?: string;
  operation?: string;
  screen?: PlatformScreen;
  surface?: string;
  sourceKind?: string;
  fetchImpl?: typeof fetch;
};

export type ResolvedRequestTimeoutContext = {
  requestClass: RequestTimeoutClass;
  timeoutMs: number;
  owner: string;
  operation: string;
  screen: PlatformScreen;
  surface: string;
  sourceKind: string;
  endpointKind: RequestTimeoutEndpointKind;
  method: string;
  urlPath: string;
  ruleId: string;
};

export class RequestTimeoutError extends Error {
  readonly requestClass: RequestTimeoutClass;
  readonly timeoutMs: number;
  readonly owner: string;
  readonly operation: string;
  readonly elapsedMs: number;
  readonly urlPath: string;

  constructor(params: {
    requestClass: RequestTimeoutClass;
    timeoutMs: number;
    owner: string;
    operation: string;
    elapsedMs: number;
    urlPath: string;
  }) {
    super(
      `${params.owner}.${params.operation} request timed out after ${params.timeoutMs}ms`,
    );
    this.name = "RequestTimeoutError";
    this.requestClass = params.requestClass;
    this.timeoutMs = params.timeoutMs;
    this.owner = params.owner;
    this.operation = params.operation;
    this.elapsedMs = params.elapsedMs;
    this.urlPath = params.urlPath;
  }
}

const nowMs = () => {
  if (typeof performance !== "undefined" && typeof performance.now === "function") {
    return performance.now();
  }
  return Date.now();
};

const trimText = (value: unknown) => String(value ?? "").trim();

const normalizeMethod = (value: unknown) => trimText(value).toUpperCase() || "GET";

const getInputUrl = (input: Parameters<typeof fetch>[0]) => {
  if (typeof input === "string") return input;
  if (input instanceof URL) return input.toString();
  if (input instanceof Request) return input.url;
  return String(input ?? "");
};

const getRequestMethod = (
  input: Parameters<typeof fetch>[0],
  init?: Parameters<typeof fetch>[1],
) => normalizeMethod(init?.method ?? (input instanceof Request ? input.method : ""));

const safeUrl = (rawUrl: string) => {
  try {
    return new URL(rawUrl);
  } catch {
    return null;
  }
};

const getEndpointKind = (pathname: string): RequestTimeoutEndpointKind => {
  if (pathname.includes("/rpc/")) return "supabase_rpc";
  if (pathname.includes("/rest/v1/")) return "supabase_rest";
  if (pathname.includes("/storage/v1/")) return "supabase_storage";
  if (pathname.includes("/functions/v1/")) return "supabase_function";
  if (pathname.includes("/auth/v1/")) return "supabase_auth";
  return "direct_fetch";
};

const extractOperationName = (endpointKind: RequestTimeoutEndpointKind, pathname: string) => {
  const cleanPath = pathname.split("?")[0];
  const parts = cleanPath.split("/").filter(Boolean);
  if (endpointKind === "supabase_rpc") return parts[parts.length - 1] ?? "rpc";
  if (endpointKind === "supabase_rest") return parts[parts.length - 1] ?? "rest";
  if (endpointKind === "supabase_storage") {
    if (parts.includes("object")) return parts.slice(parts.indexOf("object")).join("/") || "storage_object";
    return parts[parts.length - 1] ?? "storage";
  }
  if (endpointKind === "supabase_function") return parts[parts.length - 1] ?? "function";
  if (endpointKind === "supabase_auth") return parts[parts.length - 1] ?? "auth";
  return parts[parts.length - 1] ?? "fetch";
};

const matchesAny = (value: string, patterns: readonly RegExp[]) =>
  patterns.some((pattern) => pattern.test(value));

const classifyRpcRequest = (operation: string): { requestClass: RequestTimeoutClass; ruleId: string } => {
  const name = trimText(operation).toLowerCase();
  if (LIGHTWEIGHT_RPC_NAMES.has(name)) {
    return {
      requestClass: "lightweight_lookup",
      ruleId: `rpc_exact:${name}`,
    };
  }
  if (matchesAny(name, HEAVY_RPC_PATTERNS)) {
    return {
      requestClass: "heavy_report_or_pdf_or_storage",
      ruleId: `rpc_heavy:${name}`,
    };
  }
  if (matchesAny(name, UI_SCOPE_RPC_PATTERNS)) {
    return {
      requestClass: "ui_scope_load",
      ruleId: `rpc_ui:${name}`,
    };
  }
  if (matchesAny(name, MUTATION_RPC_PATTERNS)) {
    return {
      requestClass: "mutation_request",
      ruleId: `rpc_mutation:${name}`,
    };
  }
  return {
    requestClass: REQUEST_TIMEOUT_POLICY_COMPAT_DEFAULT_CLASS,
    ruleId: "rpc_default:ui_scope_load",
  };
};

const classifyFunctionRequest = (
  operation: string,
  method: string,
): { requestClass: RequestTimeoutClass; ruleId: string } => {
  const name = trimText(operation).toLowerCase();
  if (matchesAny(name, HEAVY_FUNCTION_PATTERNS)) {
    return {
      requestClass: "heavy_report_or_pdf_or_storage",
      ruleId: `function_heavy:${name}`,
    };
  }
  if (method !== "GET" && method !== "HEAD") {
    return {
      requestClass: "mutation_request",
      ruleId: `function_mutation:${name}`,
    };
  }
  return {
    requestClass: REQUEST_TIMEOUT_POLICY_COMPAT_DEFAULT_CLASS,
    ruleId: "function_default:ui_scope_load",
  };
};

const classifyByEndpoint = (
  endpointKind: RequestTimeoutEndpointKind,
  operation: string,
  method: string,
): { requestClass: RequestTimeoutClass; ruleId: string } => {
  if (endpointKind === "supabase_rpc") return classifyRpcRequest(operation);
  if (endpointKind === "supabase_function") return classifyFunctionRequest(operation, method);
  if (endpointKind === "supabase_storage") {
    return {
      requestClass: "heavy_report_or_pdf_or_storage",
      ruleId: "storage:heavy_report_or_pdf_or_storage",
    };
  }
  if (endpointKind === "supabase_auth") {
    return {
      requestClass: method === "GET" || method === "HEAD" ? "lightweight_lookup" : "mutation_request",
      ruleId: method === "GET" || method === "HEAD" ? "auth:lightweight_lookup" : "auth:mutation_request",
    };
  }
  if (endpointKind === "supabase_rest") {
    return {
      requestClass: method === "GET" || method === "HEAD" ? "ui_scope_load" : "mutation_request",
      ruleId: method === "GET" || method === "HEAD" ? "rest:ui_scope_load" : "rest:mutation_request",
    };
  }
  return {
    requestClass: REQUEST_TIMEOUT_POLICY_COMPAT_DEFAULT_CLASS,
    ruleId: "direct_fetch_default:ui_scope_load",
  };
};

const inferOwner = (endpointKind: RequestTimeoutEndpointKind) => {
  if (endpointKind === "supabase_rpc") return "supabase_rpc";
  if (endpointKind === "supabase_rest") return "supabase_rest";
  if (endpointKind === "supabase_storage") return "supabase_storage";
  if (endpointKind === "supabase_function") return "supabase_function";
  if (endpointKind === "supabase_auth") return "supabase_auth";
  return "direct_fetch";
};

const getAbortReasonText = (reason: unknown) => {
  if (reason instanceof Error) return trimText(reason.message) || reason.name;
  if (typeof reason === "string") return trimText(reason);
  if (reason && typeof reason === "object" && "message" in reason) {
    return trimText((reason as { message?: unknown }).message);
  }
  return trimText(reason) || null;
};

function isSafeTimeoutReturnEndpoint(
  resolved: ResolvedRequestTimeoutContext,
): boolean {
  return resolved.endpointKind === "supabase_auth";
}

function createTimeoutResponse(): Response {
  return new Response(
    JSON.stringify({
      error: "network_timeout",
      message: "Network timeout",
    }),
    {
      status: 599,
      headers: {
        "Content-Type": "application/json",
      },
    },
  );
}

export function resolveRequestTimeoutContext(
  input: Parameters<typeof fetch>[0],
  init?: Parameters<typeof fetch>[1],
  params?: Omit<RequestTimeoutParams, "fetchImpl">,
): ResolvedRequestTimeoutContext {
  const rawUrl = getInputUrl(input);
  const parsed = safeUrl(rawUrl);
  const urlPath = parsed?.pathname ?? rawUrl;
  const method = getRequestMethod(input, init);
  const endpointKind = getEndpointKind(urlPath);
  const inferredOperation = extractOperationName(endpointKind, urlPath);
  const classified = params?.requestClass
    ? {
        requestClass: params.requestClass,
        ruleId: "explicit_request_class",
      }
    : classifyByEndpoint(endpointKind, inferredOperation, method);
  const owner = trimText(params?.owner) || inferOwner(endpointKind);
  const operation = trimText(params?.operation) || inferredOperation;
  const requestClass = classified.requestClass;
  return {
    requestClass,
    timeoutMs: params?.timeoutMsOverride ?? REQUEST_TIMEOUT_POLICY_MS[requestClass],
    owner,
    operation,
    screen: params?.screen ?? "request",
    surface: params?.surface ?? "request_timeout",
    sourceKind:
      trimText(params?.sourceKind) ||
      `${endpointKind}:${classified.requestClass}`,
    endpointKind,
    method,
    urlPath,
    ruleId: classified.ruleId,
  };
}

function createTimeoutController(
  timeoutMs: number,
  upstreamSignal?: AbortSignal | null,
) {
  const controller = new AbortController();
  let timeoutFired = false;
  let timer: ReturnType<typeof setTimeout> | undefined;
  let timeoutSignal: AbortSignal | null = null;

  const abortWithReason = (reason: unknown) => {
    if (controller.signal.aborted) return;
    controller.abort(reason);
  };

  const onUpstreamAbort = () => abortWithReason(upstreamSignal?.reason ?? new Error("request aborted"));

  if (upstreamSignal) {
    if (upstreamSignal.aborted) {
      onUpstreamAbort();
    } else {
      upstreamSignal.addEventListener("abort", onUpstreamAbort, { once: true });
    }
  }

  const timeoutReason = new Error(`request timeout after ${timeoutMs}ms`);

  const onTimeoutAbort = () => {
    timeoutFired = true;
    abortWithReason(timeoutReason);
  };

  if (typeof AbortSignal !== "undefined" && typeof AbortSignal.timeout === "function") {
    timeoutSignal = AbortSignal.timeout(timeoutMs);
    if (timeoutSignal.aborted) {
      onTimeoutAbort();
    } else {
      timeoutSignal.addEventListener("abort", onTimeoutAbort, { once: true });
    }
  } else {
    timer = setTimeout(onTimeoutAbort, timeoutMs);
  }

  return {
    signal: controller.signal,
    didTimeout() {
      return timeoutFired;
    },
    cleanup() {
      if (timer) clearTimeout(timer);
      if (upstreamSignal) upstreamSignal.removeEventListener("abort", onUpstreamAbort);
      if (timeoutSignal) timeoutSignal.removeEventListener("abort", onTimeoutAbort);
    },
  };
}

export async function fetchWithRequestTimeout(
  input: Parameters<typeof fetch>[0],
  init?: Parameters<typeof fetch>[1],
  params?: RequestTimeoutParams,
): Promise<Response> {
  const resolved = resolveRequestTimeoutContext(input, init, params);
  const fetchImpl = params?.fetchImpl ?? fetch;
  const startedAt = nowMs();
  const controller = createTimeoutController(resolved.timeoutMs, init?.signal ?? null);
  const observation = beginPlatformObservability({
    screen: resolved.screen,
    surface: resolved.surface,
    category: "fetch",
    event: "request_timeout_discipline",
    sourceKind: resolved.sourceKind,
    trigger: "request",
    extra: {
      requestClass: resolved.requestClass,
      timeoutMs: resolved.timeoutMs,
      owner: resolved.owner,
      operation: resolved.operation,
      method: resolved.method,
      urlPath: resolved.urlPath,
      endpointKind: resolved.endpointKind,
      ruleId: resolved.ruleId,
    },
  });

  try {
    const response = await fetchImpl(input, {
      ...(init ?? {}),
      signal: controller.signal,
    });
    observation.success({
      extra: {
        requestClass: resolved.requestClass,
        timeoutMs: resolved.timeoutMs,
        owner: resolved.owner,
        operation: resolved.operation,
        method: resolved.method,
        urlPath: resolved.urlPath,
        endpointKind: resolved.endpointKind,
        ruleId: resolved.ruleId,
        timeoutFired: false,
        abortReason: null,
        httpStatus: response.status,
      },
    });
    return response;
  } catch (error) {
    const elapsedMs = Math.max(0, Math.round(nowMs() - startedAt));
    if (controller.didTimeout()) {
      const timeoutError = new RequestTimeoutError({
        requestClass: resolved.requestClass,
        timeoutMs: resolved.timeoutMs,
        owner: resolved.owner,
        operation: resolved.operation,
        elapsedMs,
        urlPath: resolved.urlPath,
      });
      observation.error(timeoutError, {
        errorStage: "timeout",
        extra: {
          requestClass: resolved.requestClass,
          timeoutMs: resolved.timeoutMs,
          owner: resolved.owner,
          operation: resolved.operation,
          method: resolved.method,
          urlPath: resolved.urlPath,
          endpointKind: resolved.endpointKind,
          ruleId: resolved.ruleId,
          timeoutFired: true,
          abortReason: "timeout",
          elapsedMs,
        },
      });

      if (isSafeTimeoutReturnEndpoint(resolved)) {
        return createTimeoutResponse();
      }

      throw timeoutError;
    }

    observation.error(error, {
      errorStage: controller.signal.aborted ? "abort" : "fetch",
      extra: {
        requestClass: resolved.requestClass,
        timeoutMs: resolved.timeoutMs,
        owner: resolved.owner,
        operation: resolved.operation,
        method: resolved.method,
        urlPath: resolved.urlPath,
        endpointKind: resolved.endpointKind,
        ruleId: resolved.ruleId,
        timeoutFired: false,
        abortReason: getAbortReasonText(controller.signal.reason),
        elapsedMs,
      },
    });
    throw error;
  } finally {
    controller.cleanup();
  }
}

